import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './theme.css';
import './style.css';
const express = require('express');
const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);
const cors = require('cors');

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
const app = express();
app.use(express.json());
app.use(cors());

// Mock Data for Dashboard
const analyticsData = [
  { name: 'Jan', sales: 4000 },
  { name: 'Feb', sales: 3000 },
  { name: 'Mar', sales: 5000 },
  { name: 'Apr', sales: 2780 },
];

// Endpoint: Analytics
app.get('/api/analytics', (req, res) => {
  res.json(analyticsData);
});

// Endpoint: Create Stripe Subscription
// Note: For Chime payouts, ensure your Chime account is linked in Stripe Dashboard > Payouts
app.post('/api/create-subscription', async (req, res) => {
  try {
    // In a real app, you would create a Stripe Product and Price first
    const paymentIntent = await stripe.paymentIntents.create({
      amount: 2999,
      currency: 'usd',
      setup_future_usage: 'off_session',
      automatic_payment_methods: { enabled: true },
    });
    res.send({ clientSecret: paymentIntent.client_secret });
  } catch (error) {
    res.status(400).send({ error: error.message });
  }
});

// Endpoint: Create Stripe Payment Intent
app.post('/api/create-payment-intent', async (req, res) => {
  try {
    const { amount } = req.body;
    const paymentIntent = await stripe.paymentIntents.create({
      amount,
      currency: 'usd',
      automatic_payment_methods: { enabled: true },
    });
    res.send({ clientSecret: paymentIntent.client_secret });
  } catch (error) {
    res.status(400).send({ error: error.message });
  }
});

const PORT = process.env.BACKEND_PORT || 5000;
app.listen(PORT, () => console.log(`Backend running on port ${PORT}`));
